#[tokio::test]
async fn test_office_xlsx_basic() {
    // XLSX spreadsheet should produce metadata and table content.
    let path = r#"xlsx/stanley_cups.xlsx"#;
    let mime_type: Option<String> = None;
    let config = Default::default();
    let result = extract_file(&path, mime_type.as_deref(), &config)
        .await
        .expect("should succeed");
    assert_eq!(
        result.mime_type.trim(),
        r#"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"#,
        "equals assertion failed"
    );
    assert!(
        result.content.len() >= 100,
        "expected length >= 100, got {}",
        result.content.len()
    );
    assert!(
        format!("{:?}", result.content).contains(r#"Team"#),
        "expected to contain: {}",
        r#"Team"#
    );
    assert!(
        format!("{:?}", result.content).contains(r#"Location"#),
        "expected to contain: {}",
        r#"Location"#
    );
    assert!(
        format!("{:?}", result.content).contains(r#"Stanley Cups"#),
        "expected to contain: {}",
        r#"Stanley Cups"#
    );
    assert!(!result.tables.is_empty(), "expected >= 1");
    assert!(result.metadata.sheet_count >= 2, "expected >= 2");
    assert!(
        format!("{:?}", result.metadata.sheet_names).contains(r#"Stanley Cups"#),
        "expected to contain: {}",
        r#"Stanley Cups"#
    );
}

